# Enter your code here. Read input from STDIN. Print output to STDOUT

def main():
    n = int(input())
    a = [list(map(int, input().split())) for _ in range(n)]
    for i in range(1, n):
        if a[i][1] != a[i-1][1]:
            if a[i][0] < a[i-1][0]:
                return "NO"
    return "YES"

print(main())
